class Solution:
    def imageSmoother(self, img: List[List[int]]) -> List[List[int]]:
        m,n=len(img),len(img[0]); ans=[[0]*n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                s=c=0
                for di in (-1,0,1):
                    for dj in (-1,0,1):
                        ni,nj=i+di,j+dj
                        if 0<=ni<m and 0<=nj<n: s+=img[ni][nj]; c+=1
                ans[i][j]=s//c
        return ans

