class Solution {
public:
    vector<vector<int>> imageSmoother(vector<vector<int>>& img) {
        int m=img.size(),n=img[0].size(); auto ans=img;
        for(int i=0;i<m;i++) for(int j=0;j<n;j++){
            int s=0,c=0;
            for(int di=-1;di<=1;di++) for(int dj=-1;dj<=1;dj++){
                int ni=i+di,nj=j+dj; if(ni>=0&&ni<m&&nj>=0&&nj<n){ s+=img[ni][nj]; c++; }
            }
            ans[i][j]=s/c;
        }
        return ans;
    }
};
